struct WalletAccount: Codable, Identifiable {
    let id: UUID
    let address: String
    let privateKeyTag: String
}

final class WalletManager: ObservableObject {
    @Published var account: WalletAccount?
    @Published var balanceText: String = "0.0"
    @Published var statusText: String = "Ready"

    private let keychain = KeychainService.shared
    private let accountStorageKey = "wallet.account"
    private let privateKeyStorageKey = "wallet.privatekey"

    init() {
        loadAccount()
    }

    func createWallet() {
        do {
            let privateKey = P256.Signing.PrivateKey()
            let publicKey = privateKey.publicKey
            let address = Self.address(from: publicKey)
            let account = WalletAccount(id: UUID(), address: address, privateKeyTag: privateKeyStorageKey)
            let privateKeyData = privateKey.rawRepresentation
            let accountData = try JSONEncoder().encode(account)
            try keychain.save(privateKeyData, for: privateKeyStorageKey)
            try keychain.save(accountData, for: accountStorageKey)
            DispatchQueue.main.async {
                self.account = account
                self.statusText = "Wallet created"
            }
        } catch {
            DispatchQueue.main.async {
                self.statusText = "Failed to create wallet"
            }
        }
    }

    func loadAccount() {
        do {
            let data = try keychain.load(for: accountStorageKey)
            let account = try JSONDecoder().decode(WalletAccount.self, from: data)
            DispatchQueue.main.async {
                self.account = account
                self.statusText = "Wallet loaded"
            }
        } catch {
            DispatchQueue.main.async {
                self.statusText = "No wallet found"
            }
        }
    }

    func deleteWallet() {
        keychain.delete(for: accountStorageKey)
        keychain.delete(for: privateKeyStorageKey)
        DispatchQueue.main.async {
            self.account = nil
            self.balanceText = "0.0"
            self.statusText = "Wallet deleted"
        }
    }

    func signTransaction(message: String) -> String? {
        do {
            let privateKeyData = try keychain.load(for: privateKeyStorageKey)
            let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
            let signature = try privateKey.signature(for: Data(message.utf8))
            return signature.derRepresentation.base64EncodedString()
        } catch {
            DispatchQueue.main.async {
                self.statusText = "Signing failed"
            }
            return nil
        }
    }

    func fetchBalance() {
        guard let account else { return }
        Task {
            do {
                let balance = try await BlockchainService.shared.fetchBalance(address: account.address)
                await MainActor.run {
                    self.balanceText = balance
                    self.statusText = "Balance updated"
                }
            } catch {
                await MainActor.run {
                    self.statusText = "Balance fetch failed"
                }
            }
        }
    }

    func sendTransaction(to: String, amount: String) {
        guard let account else { return }
        let payload = "from:\(account.address)|to:\(to)|amount:\(amount)|nonce:\(UUID().uuidString)"
        guard let signature = signTransaction(message: payload) else { return }
        Task {
            do {
                let tx = SignedTransaction(from: account.address, to: to, amount: amount, payload: payload, signature: signature)
                let result = try await BlockchainService.shared.broadcast(transaction: tx)
                await MainActor.run {
                    self.statusText = result
                }
            } catch {
                await MainActor.run {
                    self.statusText = "Transaction failed"
                }
            }
        }
    }

    private static func address(from publicKey: P256.Signing.PublicKey) -> String {
        let raw = publicKey.rawRepresentation
        let hash = SHA256.hash(data: raw)
        return "0x" + hash.compactMap { String(format: "%02x", $0) }.joined().prefix(40)
    }
}

struct SignedTransaction: Codable {
    let from: String
    let to: String
    let amount: String
    let payload: String
    let signature: String
}

final class BlockchainService {
    static let shared = BlockchainService()
    private init() {}

    func fetchBalance(address: String) async throws -> String {
        guard let url = URL(string: "https://example.com/api/balance?address=\(address)") else {
            throw URLError(.badURL)
        }
        let (_, response) = try await URLSession.shared.data(from: url)
        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw URLError(.badServerResponse)
        }
        return "0.0"
    }

    func broadcast(transaction: SignedTransaction) async throws -> String {
        guard let url = URL(string: "https://example.com/api/tx") else {
            throw URLError(.badURL)
        }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONEncoder().encode(transaction)
        let (_, response) = try await URLSession.shared.data(for: request)
        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw URLError(.badServerResponse)
        }
        return "Transaction broadcasted"
    }
}

